function LxHeroCallCtrl:CheckIsTimeHoldUp()
    if not self._recordTime then return false end

    if Time.time - self._recordTime > 1 then
        self._recordTime = nil
        return false
    end
    return true
end

function LxHeroCallCtrl:SendHeroCallReq(callRefId,count,useDiamond)
    self:RecordHeroRefIds()
    self._recordTime = Time.time
    HandlerCenter.HeroCall:HeroCallReq(callRefId,count,useDiamond)
end

