function LxHeroCallCtrl:OnCommonDisposeHeroCall(callRefId,count)
    local heroCallInfo = ModuleCenter.HeroCall:GetHeroCallInfo(callRefId)
    if not heroCallInfo then return end

    local initHeroCall = self:GetHeroCallRefData(callRefId)
    if not initHeroCall then return end

    local sendHeroCallFunc = function(useDiamond)
        self:SendHeroCallReq(callRefId,count,useDiamond)
    end

    local freeCount = heroCallInfo.freeCount
    local isFreeCall = freeCount and freeCount >= count
    if isFreeCall then
        sendHeroCallFunc()
        return
