    if count == 1 then
        callPay = initHeroCall.callPay1
        costPay = initHeroCall.cost1Pay
    else
        callPay = initHeroCall.callPay2
        costPay = initHeroCall.cost2Pay
    end
    if not costPay then
        if LOG_ERROR_ENABLED then
            printError("HeroCallRef",">> 无配置 cost1 字段")
        end
    end

    ---@type V_Item 消耗提示
    local showPayItem = callPay
    if showPayItem then
        if not CtrlCenter.Item:CheckItemEnough(showPayItem) and costPay then
            showPayItem = costPay
            callStatus = 2
        end
    end
    if showPayItem and not CtrlCenter.Item:CheckItemEnough(showPayItem,true) then
        --- 直接弹窗，不做下面逻辑
