    ---@type V_Item[]
    local reward = initHeroCall.reward
    local rewardStr = ""
    if reward then
        for i2, v2 in ipairs(reward) do
            for i, v in ipairs(v2) do
                local str = string.replace("#a1#*#a2#", LxDataHelper.GetItemName(v.refId), LxDataHelper.FormatNum(v.num * count))
                table.insert(rewardStrs, str)
            end
        end
        rewardStr = table.concat(rewardStrs, ",")
    end

    local args = {}
    if callStatus == 1 then
        args = {
            a1 = string.replace("#a1#*#a2#",LxDataHelper.GetItemName(showPayItem.refId),LxDataHelper.FormatNum(showPayItem.num)),
            a2 = rewardStr,
            a3 = count,
            a4 = self:GetNameByRefId(callRefId),
        }
    else
--[[        local first = ""
        local payNum = count
        local payItemNum
        local hasNum = ModuleCenter.Item:GetItemCount(callPay.refId)
