                end
            else
                if onePay then
                    payItemNum = showWayItem.num * onePay.num
                else
                    payItemNum = showWayItem.num * payNum
                end
            end
        else
            payItemNum = showPayItem.num
        end
        args = {a1 = first,a2 = payItemName,a3 = payItemNum,a4 = buyName,a5 = buyNum,a6 = count,a7 = callName}]]

        args = {
            a1 = string.replace("#a1#*#a2#",LxDataHelper.GetItemName(showPayItem.refId),LxDataHelper.FormatNum(showPayItem.num)),
