function LxHeroCallCtrl:GetHeroCallRefData(refId)
    local initHeroCall = self._initHeroCallMap[refId]
    if ModuleCenter.Debug.isTest then
        initHeroCall = nil
    end
    if not initHeroCall then
        local ref = GameTable.HeroCallRef[refId]
        if ref then
            local isFreeRefresh = false
            local refreshType,refreshTime
            if not string.isempty(ref.freeRefresh) then
                isFreeRefresh = true
                local freeRefresh = string.split(ref.freeRefresh,"=")
                refreshType,refreshTime = checknumber(freeRefresh[1]),checknumber(freeRefresh[2])
            end
            local getTime = ref.getTime
            local cost = ref.cost
            local mustGetItemList = {}
            if ref.mustGetItem and #ref.mustGetItem > 0 then
                for i,v in ipairs(ref.mustGetItem) do
                    v = string.split(v,"=")
                    table.insert(mustGetItemList,{
                        --- 抽取次数
                        callNum = checknumber(v[1]),
                        --- 道具id
                        itemRefId = checknumber(v[2]),
                        --- 数量
                        itemNum = checknumber(v[3])
                    })
                end
            end

            ---@type V_Item[]
            local rewards = ref.reward
            local recordRIM = {}
            local oneReward
            local reward = {}
            if rewards then
                for i2, v2 in ipairs(rewards) do
                    oneReward = LxDataHelper.ParseItemStrList(v2)
                    if oneReward and #oneReward > 0 then
                        for i, v in ipairs(oneReward) do
                            recordRIM[v.refId] = v.num
                        end
                        table.insert(reward,oneReward)
                    end
                end
            end
            for i,v in ipairs(mustGetItemList) do
                if not recordRIM[v.itemRefId] then
                    recordRIM[v.itemRefId] = true
                end
            end
            local callNum2 = checknumber(getTime[2])
            local cost1Pay,cost2Pay
            --if not string.isempty(ref.cost1) then
            --    local cost1List = string.split(ref.cost1,"|")
            --    local len = #cost1List
            --    if len > 0 then
            --        local first = LxDataHelper.ParseItem(cost1List[1])
            --        cost1Pay = first
            --        if len > 1 then
            --            cost2Pay = LxDataHelper.ParseItem(cost1List[2])
            --        else
            --            cost2Pay = {
            --                type = first.type,
            --                refId = first.refId,
            --                num = first.num * callNum2,
            --            }
            --        end
            --    end
            --end

            local cost1 = ref.cost1
            if not table.isempty(cost1) then
                local cost1List = LxDataHelper.ParseItemStrListByReward(ref.cost1)
                cost1Pay = cost1List[1][1]
                cost2Pay = cost1List[2][1]
            end

            LxDataHelper.ParseItemStrListByReward(ref.cost)
            initHeroCall = {
                refId = ref.refId,
                Type = ref.Type,
                free = ref.free,
                isFreeRefresh = isFreeRefresh,
                refreshType = refreshType,
                refreshTime = refreshTime,
                callNum1 = checknumber(getTime[1]),
                callNum2 = checknumber(getTime[2]),
                --- 抽取消耗 cost 字段 第一个
                callPay1 = LxDataHelper.ParseItem(cost[1]),
                --- 抽取消耗 cost 字段 第二个
                callPay2 = LxDataHelper.ParseItem(cost[2]),
                --- 抽取钻石消耗 cost1 字段 第一个
                cost1Pay = cost1Pay,
                --- 抽取钻石消耗 cost1 字段 第二个
                cost2Pay = cost2Pay,
                reward = reward,
                getTimeLimit = ref.getTimeLimit,
                recordNum = ref.recordNum,
                showNeed = LxDataHelper.ParseItemList(ref.showNeed),
                jackpotId = ref.jackpotId,
                mustGetItem = mustGetItemList,
                recordRIM = recordRIM,
            }
            self._initHeroCallMap[refId] = initHeroCall
        end
    end
    return initHeroCall
end

