function LxHeroCallCtrl:GetInitHeroCallJackpotList(jackpotId)
    local list = self._initHeroCallJackpotMap[jackpotId]
    if not list then
        list = {}
        ---@param v V_HeroCallJackpotRef
        for k,v in pairs(GameTable.HeroCallJackpotRef) do
            if v.jackpotId == jackpotId then
                table.insert(list,{
                    refId = v.refId,
                    jackpotId = v.jackpotId,
                    jackpotId1 = v.jackpotId1,
                    showKind = v.showKind,
                    reward = self:_GetHeroCallJackpotHeroReward(v.reward),
                    sort = v.sort,
                    probabilityShow = v.probabilityShow,
                    ItemQuality = v.ItemQuality,
                    isLock = v.isLock,
                    rate = v.rate,
                    wantGet = v.wantGet,
                })
            end
        end
        table.sort(list,function(a,b)
            return a.sort > b.sort
        end)
        self._initHeroCallJackpotMap[jackpotId] = list
    end
    return list
end

function LxHeroCallCtrl:GetHeroCallJackpotWishList(callRefId)
    local initHeroCall = self:GetHeroCallRefData(callRefId)
    if not initHeroCall then return {} end
    local jackpotId = initHeroCall.jackpotId
    local jackpotList = self:GetInitHeroCallJackpotList(jackpotId)
    local list = {}
    if callRefId == HeroCall_RefIds.Wish then
        for i,v in ipairs(jackpotList) do
            --if not string.isempty(v.probabilityShow) then
            --end
            if v.jackpotId1 == 0 and v.wantGet == 0 then
                table.insert(list,v)
            end
        end
    else
        for i,v in ipairs(jackpotList) do
            if not string.isempty(v.probabilityShow) then
                if v.wantGet == 0 then
                    table.insert(list,v)
                end
            end
        end
    end
    return list
end



function LxHeroCallCtrl:GetHeroCallPublicityList(callRefId)
    local initHeroCall = self:GetHeroCallRefData(callRefId)
    if not initHeroCall then return {} end

    if not self._initJackpotIdMap then
        self._initJackpotIdMap = {}
    end
    local initJackporIds = self._initJackpotIdMap[callRefId]
    if not initJackporIds then
        initJackporIds = self:_GetCommonCallHeroList(initHeroCall.jackpotId)
        self._initJackpotIdMap[callRefId] = initJackporIds
    end
    return initJackporIds
end

function LxHeroCallCtrl:_GetCommonCallHeroList(jackpotId)
    local showKindMap = {}
    local showKind,reward,sort,ItemQuality
    ---@type V_HeroCallJackpotRef[]
    local jackpotList = self:GetInitHeroCallJackpotList(jackpotId)
    for i,v in ipairs(jackpotList) do
        showKind = v.showKind
        reward = v.reward or {}
        if showKind and showKind > 0 and #reward > 0 then
            local showKinds = showKindMap[showKind]
            if not showKinds then
                showKinds = {}
                showKindMap[showKind] = showKinds
            end
            sort = v.sort
            ItemQuality = v.ItemQuality
            for idx,val in ipairs(reward) do
                table.insert(showKinds,{
                    item = val,
                    sort = sort,
                    quality = ItemQuality,
                })
            end
        end
    end
    local initJackporIds = {}
    for k,v in pairs(showKindMap) do
        table.sort(v,function(a,b)
            local ItemQualityA,ItemQualityB = a.quality,b.quality
            if ItemQualityA ~= ItemQualityB then return ItemQualityA > ItemQualityB end
            return a.sort > b.sort
        end)
        table.insert(initJackporIds,{
            title = I18nText(k),
            sort = k,
            showItemList = v,
        })
    end
    table.sort(initJackporIds,function(a,b) return a.sort < b.sort end)
    return initJackporIds
end


