--- 获得最高品质的次数
function LxHeroCallCtrl:GetMustGetCount(refId)
    local heroCallInfo = ModuleCenter.HeroCall:GetHeroCallInfo(refId)
    if not heroCallInfo then return end

    local mustGetCount = heroCallInfo.mustGetCount
    if #mustGetCount < 1 then return end

    if refId == HeroCall_RefIds.Wish then
        local heroName = ""
        local wish = heroCallInfo.wish
        if wish and #wish > 0 then
            heroName = LxDataHelper.GetHeroName(wish[1])
        end
        return {
            quality = mustGetCount[1].key,
            heroName = heroName,
            residueNum = mustGetCount[1].value
        }
    end

    local quality,residueNum
    for i,v in ipairs(mustGetCount) do
        if not quality then
            quality = v.key
            residueNum = v.value
        elseif quality and quality < v.key then
            quality = v.key
            residueNum = v.value
        end
    end
    if not quality or not residueNum then return end
    return {
        quality = quality,
        residueNum = residueNum,
        heroClassName = LxDataHelper.GetQualityHeroClassName(quality),
    }
end


--- 获取累计召唤次数
function LxHeroCallCtrl:GetCallAddNumStr(refId)
    ---@type LxHeroCallInfo
    local heroCallInfo = ModuleCenter.HeroCall:GetHeroCallInfo(refId)
    if not heroCallInfo then return end

    local initHeroCall = self:GetHeroCallRefData(refId)
    if not initHeroCall then return end

    local mustGetItem = initHeroCall.mustGetItem
    if mustGetItem and #mustGetItem > 0 then
        local mustCallNum = mustGetItem[#mustGetItem].callNum
        local totalCount = heroCallInfo.totalCount
        local modulo = totalCount % mustCallNum
        local callNum,itemId,itemNum
        if modulo == 0 then
            local info = mustGetItem[1]
            callNum = info.callNum
            itemId = info.itemRefId
            itemNum = info.itemNum
        else
            local tempIdx
            for i,v in ipairs(mustGetItem) do
                if v.callNum - modulo > 0 then
                    tempIdx = i
                    break
                end
            end
            if not tempIdx then tempIdx = 1 end

            local info = mustGetItem[tempIdx]
            callNum = info.callNum
            itemId = info.itemRefId
            itemNum = info.itemNum
        end
        return {
            leftStr = string.replace(I18nText(4005),modulo,callNum),
            rightStr = string.replace(I18nText(4007),itemNum),
            itemId = itemId,
        }
    end
end


