                showQuality = checknumber(v[2]),
            })
        end
        self._heroCallShows = heroCallShows
    end
    local quality
    --local roleLv = ModuleCenter.Role:GetRoleLevel()
    local buildingLv = ModuleCenter.Building:GetBuildingLvl(BuildingType.HuoLu)
    local data
    local len = #heroCallShows
    for i = len,1,-1 do
        data = heroCallShows[i]
        if data and data.buildingLv <= buildingLv then
            quality = data.showQuality
            break
        end
    end
    if not quality then quality = heroCallShows[1].showQuality end
    return quality
end

---@param thingsInfo LxThingsInfo
---@param extraData table key-value
function LxHeroCallCtrl:OpenHeroCallResult(thingsInfo,callRefId,extraData)
    if not thingsInfo then return end

    --ModuleCenter.Debug:WriteFileByLuaData({ thingsInfo, callRefId, extraData }, "OpenHeroCallResult")

    ---@type table<number, LxHeroInfo>
    local heros = thingsInfo.heroes
    local showQHNum = 0
    ---@type LxHeroInfo[] 需要展示的高品质的英雄
    local showQualityHeroList = {}
    local heroCallShow1Map = self._heroCallShow1Map
    local recordHeroRefIds = self._recordHeroRefIds or {}
    local initQuality
    local insHero = false
    local heroRefId
    local showQuality = self:GetHeroCallShowQuality()
    for i,v in ipairs(heros) do
        insHero = false
        heroRefId = v.refId
        if heroCallShow1Map[heroRefId] and not recordHeroRefIds[heroRefId] then
            --- 抽卡时首次获得某英雄，必定展示（无视heroCallShow字段影响）
            insHero = true
        else
            initQuality = LxDataHelper.GetHeroInitQuality(heroRefId) or 0
            insHero = initQuality >= showQuality
        end
        if insHero then
            table.insert(showQualityHeroList,v)
            showQHNum = showQHNum + 1
        end
    end

    local openHeroCallResultFunc = function()
        local data = {
            thingsInfo = thingsInfo,
            callRefId = callRefId,
            extraData = extraData,
        }
        local uiKey = UiNames.HeroCallResult
        --ModuleCenter.Debug:WriteFileByLuaData(data, "HeroCallResult")
        if IsOpenPanel(uiKey) then
            RefreshPanel(uiKey,data)
        else
            ShowPanel(uiKey,data)
        end
    end
    if showQHNum > 0 then
        --- 展示高品质获得后再展示获得界面
        local data = {
            showHeroList = showQualityHeroList,
            callBackFunc = openHeroCallResultFunc,
        }
        --ModuleCenter.Debug:WriteFileByLuaData(showQualityHeroList, "HeroCallHighQuality")
        local uiKey = UiNames.HeroCallHighQuality
        if IsOpenPanel(uiKey) then
            RefreshPanel(uiKey,data)
        else
            ShowPanel(uiKey,data)
        end
    else
        --- 展示获得界面
        openHeroCallResultFunc()
    end
end


