--- 获取
function LxHeroCallCtrl:GetHeroCallRed()
    local heroCallInfos = ModuleCenter.HeroCall:GetHeroCallInfos()
    if not heroCallInfos then return 0 end
    local num = 0
    for k,v in pairs(heroCallInfos) do
        num = num + v.freeCount
    end
    return num
end

function LxHeroCallCtrl:GetHeroCallAwardRefList()
    if not self._initHeroCallAwardRefList then
        local list = {}
        for k,v in pairs(GameTable.HeroCallAwardRef) do
            table.insert(list,{
                refId = k,
                rank = v.rank,
                reward = v.reward,
            })
        end
        table.sort(list,function(a,b) return a.refId < b.refId end)
        self._initHeroCallAwardRefList = list
    end
    return self._initHeroCallAwardRefList
end


