--- 检查背包容量是否足够
function LxHeroCallCtrl:CheckHeroBagIsEnough(callNum)
    local bagInfo = ModuleCenter.Hero:GetHeroBagNumInfo()
    local maxBagNum = bagInfo.maxBagNum -- 背包最大容量
    local heroNum = ModuleCenter.Hero:GetHeroNums() -- 英雄数量
    if callNum <= maxBagNum - heroNum then
        return true
    end

    local bagNumInfo = ModuleCenter.Hero:GetHeroBagNumInfo()
    local bagexpandNum = bagNumInfo.bagexpandNum or 0
    local buyIdx = bagexpandNum + 1
    local initHeroBagNumBuyList = CtrlCenter.Hero:GetInitHeroBagNumBuyList()

    if buyIdx > #initHeroBagNumBuyList then -- 背包不足
        ShowAlert({
            refId = 3003,
            actionOk = function()
                CtrlCenter.City:MoveToBuildObjPanel(BuildingType.YingHunDian)
            end,

        })
    else
        ---@type V_Item
        local payItem = initHeroBagNumBuyList[buyIdx]
        ShowAlert({
            refId = 3002,
            actionOk = function()
                HandlerCenter.Hero:HeroBagExpandReq()
            end,
            args = {
                a1 = payItem.num,
                a2 = payItem.openNum,
            },
            costArgs = {
                refId = payItem.refId,
                num = payItem.num,
            }
        })
    end
    return false
end
--- 根据召唤类型 获取对应红点
function LxHeroCallCtrl:CheckCallHeroRedByRefId(refId, funcId)
    if funcId then
        local isOpen = CtrlCenter.FuncOpen:IsFuncOpen(funcId)
        if not isOpen then
            return false
        end
    end
    local heroCallInfo = ModuleCenter.HeroCall:GetHeroCallInfo(refId)
    if  heroCallInfo then
        if heroCallInfo.freeCount > 0 then
            return true
        end
    end
    local initHeroCall = self:GetHeroCallRefData(refId)
    if not initHeroCall then return end
    ---@type V_Item 抽取消耗
    local callPay = initHeroCall.callPay2

    local costRefId = callPay.refId
    local hasNum = ModuleCenter.Item:GetItemCount(costRefId)
    local num = callPay.num or 1
    local isFull = hasNum >= num
    return isFull
end

return LxHeroCallCtrl